 1→import type { Page } from '@playwright/test'
 2→import type { ElementCheck } from './types'
 3→
 4→export interface VerifyDetail {
 5→  label: string
 6→  selector: string
 7→  passed: boolean
 8→}
 9→
10→export interface VerifyResult {
11→  passed: number
12→  failed: number
13→  details: VerifyDetail[]
14→}
15→
16→export async function verify(
17→  page: Page,
18→  checks: ElementCheck[],
19→): Promise<VerifyResult> {
20→  const details: VerifyDetail[] = []
21→  let passed = 0
22→  let failed = 0
23→
24→  for (const check of checks) {
25→    let ok = false
26→    try {
27→      ok = await page.locator(check.selector).isVisible({ timeout: 3000 })
28→    } catch {
29→      ok = false
30→    }
31→
32→    if (ok) {
33→      passed++
34→      console.log(`  PASS  ${check.label}`)
35→    } else {
36→      failed++
37→      console.log(`  FAIL  ${check.label}  (${check.selector})`)
38→    }
39→
40→    details.push({ label: check.label, selector: check.selector, passed: ok })
41→  }
42→
43→  return { passed, failed, details }
44→}
